return items.map(item => {
  const body = item.json.body || {};

  const messages =
    body.artifact?.messages ||
    body.messages ||
    body.message?.artifact?.messages ||
    [];

  const getMessageText = (m) => {
    return m.message || m.content || m.text || "";
  };

  const cleanRole = (role) => (role || "").toLowerCase();

  const usableMessages = Array.isArray(messages)
    ? messages.filter(m => {
        const role = cleanRole(m.role);
        return role !== "system" && role !== "developer" && role !== "tool";
      })
    : [];

  const conversationMessages = usableMessages
    .map(m => {
      const role = cleanRole(m.role);
      const text = getMessageText(m);

      if (!text) return "";

      if (role === "bot" || role === "assistant") {
        return `Assistant: ${text}`;
      }

      if (role === "user") {
        return `Patient: ${text}`;
      }

      return `${role || "Speaker"}: ${text}`;
    })
    .filter(Boolean)
    .join("\n");

  const userOnlyText = usableMessages
    .filter(m => cleanRole(m.role) === "user")
    .map(m => getMessageText(m))
    .filter(Boolean)
    .join("\n");

  function titleCaseWord(word) {
    if (!word) return "";
    return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
  }

  function titleCaseName(name) {
    return name
      .trim()
      .replace(/[.,!?]+$/g, "")
      .split(/\s+/)
      .filter(Boolean)
      .map(titleCaseWord)
      .join(" ");
  }

  function formatJoinedLetters(joined) {
    if (!joined) return "";

    joined = joined.toLowerCase().replace(/[^a-z]/g, "");

    // Common demo case: Ammad Khan spelled as a m m a d k h a n
    if (joined.endsWith("khan") && joined.length > 4) {
      const firstName = joined.slice(0, -4);
      return `${titleCaseWord(firstName)} Khan`;
    }

    return titleCaseWord(joined);
  }

  function extractSpelledNameFromText(text) {
    if (!text) return "";

    let lower = text.toLowerCase();

    // Only focus on the part after phrases like "name as ..."
    const segmentMatch =
      lower.match(/name\s+as\s+(.+?)(?:is that correct|\?|$)/i) ||
      lower.match(/name\s+is\s+(.+?)(?:is that correct|\?|$)/i) ||
      lower.match(/have your name as\s+(.+?)(?:is that correct|\?|$)/i);

    if (segmentMatch && segmentMatch[1]) {
      lower = segmentMatch[1];
    }

    // Convert "d for dog" to "d"
    lower = lower.replace(/\b([a-z])\s+for\s+[a-z]+\b/g, "$1");

    // Convert "double m" to "m m"
    lower = lower.replace(/\bdouble\s+([a-z])\b/g, "$1 $1");

    // Convert "two m" to "m m"
    lower = lower.replace(/\btwo\s+([a-z])\b/g, "$1 $1");

    const letters = lower.match(/\b[a-z]\b/g);

    if (!letters || letters.length < 3) {
      return "";
    }

    const joined = letters.join("");

    // Ignore tiny accidental captures
    if (joined.length < 3) {
      return "";
    }

    return formatJoinedLetters(joined);
  }

  function extractNormalName(text) {
    if (!text) return "";

    const match = text.match(
      /(?:my name is|i am|i'm|this is|it is|it's)\s+([a-zA-Z][a-zA-Z\s'-]{1,60}?)(?:,|\.|\s+spelled|\s+spell|\s+i have|\s+and\s+i|\s+with|\n|$)/i
    );

    if (!match || !match[1]) return "";

    let name = match[1].trim();

    name = name
      .replace(/\b(have|fever|sore|throat|pain|cough|allergy|allergies|medication|medications|symptoms|no|none)\b.*$/i, "")
      .trim();

    if (name.length < 2) return "";

    return titleCaseName(name);
  }

  function extractLastConfirmedAssistantName(messages) {
    let confirmedName = "";

    for (let i = 0; i < messages.length - 1; i++) {
      const current = messages[i];
      const next = messages[i + 1];

      const currentRole = cleanRole(current.role);
      const nextRole = cleanRole(next.role);

      if (!(currentRole === "bot" || currentRole === "assistant")) continue;
      if (nextRole !== "user") continue;

      const assistantText = getMessageText(current);
      const userReply = getMessageText(next).toLowerCase();

      const userConfirmed =
        /\b(yes|yeah|yep|correct|right|that's right|that is right|exactly|perfect|confirmed)\b/i.test(userReply);

      if (!userConfirmed) continue;

      const spelledName = extractSpelledNameFromText(assistantText);
      if (spelledName) {
        confirmedName = spelledName;
        continue;
      }

      const normalName =
        assistantText.match(/name\s+(?:as|is)\s+([A-Z][a-zA-Z'-]+(?:\s+[A-Z][a-zA-Z'-]+){0,3})/i);

      if (normalName && normalName[1]) {
        confirmedName = titleCaseName(normalName[1]);
      }
    }

    return confirmedName;
  }

  function extractBestUserName(text) {
    const spelled = extractSpelledNameFromText(text);
    if (spelled) return spelled;

    const normal = extractNormalName(text);
    if (normal) return normal;

    return "";
  }

  // Priority:
  // 1. Last name confirmed by the user
  // 2. User's own spelling/name
  // 3. Vapi/customer field fallback
  const confirmedAssistantName = extractLastConfirmedAssistantName(usableMessages);
  const userName = extractBestUserName(userOnlyText);

  const extractedPatientName =
    confirmedAssistantName ||
    userName ||
    body.patient_name ||
    body.patientName ||
    body.customer?.name ||
    "Not mentioned";

  const callId =
    body.call?.id ||
    body.message?.call?.id ||
    body.callId ||
    body.id ||
    "Not available";

  // Prefer our cleaned conversation transcript so system prompts are removed
  const transcript =
    conversationMessages ||
    body.artifact?.transcript ||
    body.message?.artifact?.transcript ||
    body.transcript ||
    "No transcript received";

  return {
    json: {
      call_id: callId,
      patient_name: extractedPatientName,
      clinical_transcript: transcript,
      user_only_text: userOnlyText,
      name_source: confirmedAssistantName
        ? "confirmed_assistant_name"
        : userName
        ? "user_name_or_spelling"
        : "fallback"
    }
  };
});

const openAiOutput = items[0].json;

const text =
  openAiOutput.output?.[0]?.content?.[0]?.text ||
  openAiOutput.text ||
  openAiOutput.response ||
  "";

const cleaned = String(text)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let aiData;

try {
  aiData = JSON.parse(cleaned);
} catch (error) {
  aiData = {
    patient_name: "Not mentioned",
    chief_complaint: "Not mentioned",
    symptoms: "Not mentioned",
    duration: "Not mentioned",
    severity: "Not mentioned",
    relevant_negatives: "Not mentioned",
    past_medical_history: "Not mentioned",
    medications: "Not mentioned",
    allergies: "Not mentioned",
    assessment: "Not mentioned",
    plan: "Not mentioned",
    clinical_note: cleaned || "No clinical note generated"
  };
}

const transcriptData = $("Extract Call Transcript").first().json;

return [
  {
    json: {
      created_at: new Date().toLocaleString("en-PK", {
        timeZone: "Asia/Karachi"
      }),

      call_id: transcriptData.call_id || "Not available",

      patient_name:
      transcriptData.patient_name && transcriptData.patient_name !== "Not mentioned"
      ? transcriptData.patient_name
      : aiData.patient_name || "Not mentioned",

      chief_complaint: aiData.chief_complaint || "Not mentioned",
      symptoms: aiData.symptoms || "Not mentioned",
      duration: aiData.duration || "Not mentioned",
      severity: aiData.severity || "Not mentioned",
      relevant_negatives: aiData.relevant_negatives || "Not mentioned",
      past_medical_history: aiData.past_medical_history || "Not mentioned",
      medications: aiData.medications || "Not mentioned",
      allergies: aiData.allergies || "Not mentioned",
      assessment: aiData.assessment || "Not mentioned",
      plan: aiData.plan || "Not mentioned",

      full_transcript:
        transcriptData.clinical_transcript || "No transcript received",

      clinical_note: aiData.clinical_note || "No clinical note generated",
      status: "Draft - clinician review required"
    }
  }
];
